// ----- Node 2: Validate -----
// Checks origin, custom header, and payload shape.
// Returns cleaned data (status 200) or an error object.

const item = $input.first().json;
const headers = item.headers || {};
const body = item.body || {};

// 1. Origin check
const origin = headers['origin'] || '';
const allowed = [
  'https://docs.strapi.io',
  'https://docs-next.strapi.io',
  'http://localhost:3000'
];
if (!allowed.some(o => origin.startsWith(o))) {
  return [{ json: { error: 'origin_rejected', status: 403 } }];
}

// 2. Custom header check
const source = headers['x-feedback-source'] || '';
if (source !== 'docs-widget') {
  return [{ json: { error: 'source_header_missing', status: 403 } }];
}

// 3. Vote validation
const validVotes = ['up', 'down'];
if (!validVotes.includes(body.vote)) {
  return [{ json: { error: 'invalid_vote', status: 400 } }];
}

// 4. Kind validation
const validKinds = ['page', 'selection', 'element'];
if (!validKinds.includes(body.kind)) {
  return [{ json: { error: 'invalid_kind', status: 400 } }];
}

// 5. Comment required for downvotes, min 20 chars
if (body.vote === 'down') {
  if (!body.comment || body.comment.trim().length < 20) {
    return [{ json: { error: 'comment_required_for_downvote', status: 400 } }];
  }
}

// 6. Comment max length
if (body.comment && body.comment.length > 2000) {
  return [{ json: { error: 'comment_too_long', status: 400 } }];
}

// All checks passed -- return cleaned data
return [{
  json: {
    vote: body.vote,
    kind: body.kind,
    comment: (body.comment || '').trim().slice(0, 2000),
    pagePath: (body.pagePath || '').slice(0, 500),
    pageId: (body.pageId || '').slice(0, 500),
    pageTitle: (body.pageTitle || '').slice(0, 500),
    honeypot: body._hp || '',
    ip: headers['x-forwarded-for'] || 'unknown',
    userAgent: headers['user-agent'] || '',
    status: 200
  }
}];
